        assert.strictEqual(c2.isInfinite(), true);
        assert.strictEqual(c3.isInfinite(), true);
        assert.strictEqual(c4.isInfinite(), true);
        assert.strictEqual(c5.isInfinite(), true);
        done();
    });

    it('test NaN components are not considered infinite', function(done) {
        // Test complex numbers with NaN components
        let c1 = new complex_js(NaN, 0);
        let c2 = new complex_js(0, NaN);
        let c3 = new complex_js(NaN, NaN);

        assert.strictEqual(c1.isInfinite(), false);
        assert.strictEqual(c2.isInfinite(), false);
        assert.strictEqual(c3.isInfinite(), false);
